// HasUser applies the HasEdge predicate on the "user" edge.
func HasUser() predicate.RechargeOrder {
	return predicate.RechargeOrder(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, UserTable, UserColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasUserWith applies the HasEdge predicate on the "user" edge with a given conditions (other predicates).
func HasUserWith(preds ...predicate.User) predicate.RechargeOrder {
	return predicate.RechargeOrder(func(s *sql.Selector) {
		step := newUserStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// HasReferralCommissions applies the HasEdge predicate on the "referral_commissions" edge.
func HasReferralCommissions() predicate.RechargeOrder {
	return predicate.RechargeOrder(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.O2M, false, ReferralCommissionsTable, ReferralCommissionsColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasReferralCommissionsWith applies the HasEdge predicate on the "referral_commissions" edge with a given conditions (other predicates).
func HasReferralCommissionsWith(preds ...predicate.ReferralCommission) predicate.RechargeOrder {
	return predicate.RechargeOrder(func(s *sql.Selector) {
		step := newReferralCommissionsStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RechargeOrder) predicate.RechargeOrder {
	return predicate.RechargeOrder(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RechargeOrder) predicate.RechargeOrder {
	return predicate.RechargeOrder(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RechargeOrder) predicate.RechargeOrder {
	return predicate.RechargeOrder(sql.NotPredicates(p))
}
